    public boolean processTransaction(Connection connection, long accountId, BigDecimal transactionAmount, String transactionType) throws SQLException {
        ReentrantLock lock = accountLocks.computeIfAbsent(accountId, k -> new ReentrantLock());
        lock.lock();
        
        try {
            connection.setAutoCommit(false);
            connection.setTransactionIsolation(Connection.TRANSACTION_SERIALIZABLE);
            
            BigDecimal currentBalance = null;
            String selectSQL = "SELECT balance FROM accounts WHERE account_id = ? FOR UPDATE";
            
            try (PreparedStatement selectStmt = connection.prepareStatement(selectSQL)) {
                selectStmt.setLong(1, accountId);
                
                try (ResultSet rs = selectStmt.executeQuery()) {
                    if (rs.next()) {
                        currentBalance = rs.getBigDecimal("balance");
                    } else {
                        connection.rollback();
                        return false;
                    }
                }
            }
            
            if (transactionAmount == null || transactionAmount.compareTo(BigDecimal.ZERO) <= 0) {
                connection.rollback();
                return false;
            }
            
            BigDecimal newBalance;
            if ("DEBIT".equalsIgnoreCase(transactionType) || "WITHDRAWAL".equalsIgnoreCase(transactionType)) {
                if (currentBalance.compareTo(transactionAmount) < 0) {
                    connection.rollback();
                    return false;
                }
                newBalance = currentBalance.subtract(transactionAmount);
            } else if ("CREDIT".equalsIgnoreCase(transactionType) || "DEPOSIT".equalsIgnoreCase(transactionType)) {
                newBalance = currentBalance.add(transactionAmount);
            } else {
                connection.rollback();
                return false;
            }
            
            String updateSQL = "UPDATE accounts SET balance = ?, last_updated = CURRENT_TIMESTAMP WHERE account_id = ?";
            try (PreparedStatement updateStmt = connection.prepareStatement(updateSQL)) {
                updateStmt.setBigDecimal(1, newBalance);
                updateStmt.setLong(2, accountId);
                
                int rowsAffected = updateStmt.executeUpdate();
                if (rowsAffected != 1) {
                    connection.rollback();
                    return false;
                }
            }
            
            String insertTransactionSQL = "INSERT INTO transactions (account_id, transaction_type, amount, balance_after, transaction_date) VALUES (?, ?, ?, ?, CURRENT_TIMESTAMP)";
            try (PreparedStatement insertStmt = connection.prepareStatement(insertTransactionSQL)) {
                insertStmt.setLong(1, accountId);
                insertStmt.setString(2, transactionType);
                insertStmt.setBigDecimal(3, transactionAmount);
                insertStmt.setBigDecimal(4, newBalance);
                insertStmt.executeUpdate();
            }
            
            connection.commit();
            return true;
            
        } catch (SQLException e) {
            try {
                connection.rollback();
            } catch (SQLException rollbackEx) {
                rollbackEx.printStackTrace();
            }
            throw e;
        } finally {
            try {
                connection.setAutoCommit(true);
            } catch (SQLException e) {
                e.printStackTrace();
            }
            lock.unlock();
        }
    }
    
